-- Retrieve all columns and all rows
SELECT * FROM employees;

-- Retrieve only specific columns
SELECT name, salary FROM employees;

-- Specify conditions with WHERE
SELECT name, salary
FROM employees
WHERE salary >= 350000;

-- Multiple conditions (AND / OR)
SELECT name, age, dept_id
FROM employees
WHERE dept_id = 1 AND age >= 25;

SELECT name FROM employees
WHERE dept_id = 1 OR dept_id = 2;

-- IN clause for specifying multiple values (concise alternative to OR)
SELECT name FROM employees
WHERE dept_id IN (1, 2, 3);

-- LIKE clause for pattern matching (% = any string)
SELECT name FROM employees
WHERE name LIKE 'Yamada%';  -- Names starting with "Yamada"

-- BETWEEN for range specification
SELECT name, salary FROM employees
WHERE salary BETWEEN 300000 AND 400000;

-- NULL comparison (use IS NULL / IS NOT NULL, not =)
SELECT name FROM employees
WHERE email IS NOT NULL;

