import java.sql.*;

// Variable declaration and initialization
String url  = "jdbc:mysql://localhost:3306/company_db";
String user = "root";
String pass = "password";

// Code that may throw an exception
try (Connection conn = DriverManager.getConnection(url, user, pass);
     Statement stmt = conn.createStatement();
     ResultSet rs = stmt.executeQuery(
         "SELECT emp_id, name, salary FROM employees")) {

    // Loop while condition is true
    while (rs.next()) {
        int id       = rs.getInt("emp_id");
        String name  = rs.getString("name");
        double salary = rs.getDouble("salary");
        System.out.printf("%d: %s (%.0f)%n", id, name, salary);
    }
} catch (SQLException e) {
    System.err.println("DB error: " + e.getMessage());
    e.printStackTrace();
}

// Variable declaration and initialization
String url = "jdbc:mysql://localhost:3306/company_db";

// Code that may throw an exception
try (Connection conn = DriverManager.getConnection(url, "root", "pass")) {

    // INSERT — Adding data
    String insertSql = "INSERT INTO employees (name, email, age, salary, dept_id, hire_date) VALUES (?, ?, ?, ?, ?, ?)";
    // Code that may throw an exception
    try (PreparedStatement ps = conn.prepareStatement(insertSql)) {
        ps.setString(1, "Kenta Takahashi");
        ps.setString(2, "takahashi@example.com");
        ps.setInt(3, 27);
        ps.setDouble(4, 320000);
        ps.setInt(5, 1);
        ps.setDate(6, java.sql.Date.valueOf("2025-04-01"));
        int rows = ps.executeUpdate();
        System.out.println(rows + " row(s) inserted");
    }

    // UPDATE — Modifying data
    String updateSql = "UPDATE employees SET salary = ? WHERE name = ?";
    // Code that may throw an exception
    try (PreparedStatement ps = conn.prepareStatement(updateSql)) {
        ps.setDouble(1, 350000);
        ps.setString(2, "Kenta Takahashi");
        ps.executeUpdate();
    }

} catch (SQLException e) {
    e.printStackTrace();
}

